export const getRandomListings = (count: number = 10) => MOCK_LISTINGS.slice(0, count);
export const getListingsByCategory = (category: string) => MOCK_LISTINGS.filter(listing => listing.category === category);
export const getListingById = (id: number) => MOCK_LISTINGS.find(listing => listing.id === id);
export const getUserListings = (userId: number) => MOCK_LISTINGS.filter(listing => listing.seller.id === userId);
